package main

import "errors"

// Compliant: Using early returns to reduce nesting
func processOrder(order Order) error {
    if order == nil {
        return errors.New("order is nil")
    }

    if !order.IsValid() {
        return errors.New("invalid order")
    }

    if err := validateCustomer(order.Customer); err != nil {
        return err
    }

    if err := validateItems(order.Items); err != nil {
        return err
    }

    if err := validatePayment(order.PaymentMethod); err != nil {
        return err
    }

    return processOrderItems(order)
}

func validateCustomer(customer *Customer) error {
    if customer == nil {
        return errors.New("no customer")
    }
    if !customer.IsActive() {
        return errors.New("inactive customer")
    }
    return nil
}

func validateItems(items []Item) error {
    if items == nil || len(items) == 0 {
        return errors.New("no items in order")
    }
    return nil
}

func validatePayment(payment *PaymentMethod) error {
    if payment == nil {
        return errors.New("no payment method")
    }
    if !payment.IsValid() {
        return errors.New("invalid payment method")
    }
    return nil
}

func processOrderItems(order Order) error {
    for _, item := range order.Items {
        if err := processOrderItem(item, order); err != nil {
            return err
        }
    }
    return nil
}

func processOrderItem(item Item, order Order) error {
    if !item.IsAvailable() {
        return errors.New("item not available")
    }
    if item.Price <= 0 {
        return errors.New("invalid price")
    }
    return processItem(item, order)
}
